    30→#include "server.h"
    31→#include <fcntl.h>
    32→
    33→/* =============================================================================
    34→ * Global state for ACLs
    35→ * ==========================================================================*/
    36→
    37→rax *Users; /* Table mapping usernames to user structures. */
    38→
    39→user *DefaultUser;  /* Global reference to the default user.
    40→                       Every new connection is associated to it, if no
    41→                       AUTH or HELLO is used to authenticate with a
    42→                       different user. */
    43→
    44→list *UsersToLoad;  /* This is a list of users found in the configuration file
    45→                       that we'll need to load in the final stage of Redis
    46→                       initialization, after all the modules are already
    47→                       loaded. Every list element is a NULL terminated
    48→                       array of SDS pointers: the first is the user name,
    49→                       all the remaining pointers are ACL rules in the same
    50→                       format as ACLSetUser(). */
    51→
    52→struct ACLCategoryItem {
    53→    const char *name;
    54→    uint64_t flag;
    55→} ACLCommandCategories[] = {
    56→    {"keyspace", CMD_CATEGORY_KEYSPACE},
    57→    {"read", CMD_CATEGORY_READ},
    58→    {"write", CMD_CATEGORY_WRITE},
    59→    {"set", CMD_CATEGORY_SET},
    60→    {"sortedset", CMD_CATEGORY_SORTEDSET},
    61→    {"list", CMD_CATEGORY_LIST},
    62→    {"hash", CMD_CATEGORY_HASH},
    63→    {"string", CMD_CATEGORY_STRING},
    64→    {"bitmap", CMD_CATEGORY_BITMAP},
    65→    {"hyperloglog", CMD_CATEGORY_HYPERLOGLOG},
    66→    {"geo", CMD_CATEGORY_GEO},
    67→    {"stream", CMD_CATEGORY_STREAM},
    68→    {"pubsub", CMD_CATEGORY_PUBSUB},
    69→    {"admin", CMD_CATEGORY_ADMIN},
    70→    {"fast", CMD_CATEGORY_FAST},
    71→    {"slow", CMD_CATEGORY_SLOW},
    72→    {"blocking", CMD_CATEGORY_BLOCKING},
    73→    {"dangerous", CMD_CATEGORY_DANGEROUS},
    74→    {"connection", CMD_CATEGORY_CONNECTION},
    75→    {"transaction", CMD_CATEGORY_TRANSACTION},
    76→    {"scripting", CMD_CATEGORY_SCRIPTING},
    77→    {NULL,0} /* Terminator. */
    78→};
    79→
    80→struct ACLUserFlag {
    81→    const char *name;
    82→    uint64_t flag;
    83→} ACLUserFlags[] = {
    84→    {"on", USER_FLAG_ENABLED},
    85→    {"off", USER_FLAG_DISABLED},
    86→    {"allkeys", USER_FLAG_ALLKEYS},
    87→    {"allcommands", USER_FLAG_ALLCOMMANDS},
    88→    {"nopass", USER_FLAG_NOPASS},
    89→    {NULL,0} /* Terminator. */
    90→};
    91→
    92→void ACLResetSubcommandsForCommand(user *u, unsigned long id);
    93→void ACLResetSubcommands(user *u);
    94→void ACLAddAllowedSubcommand(user *u, unsigned long id, const char *sub);
    95→
    96→/* =============================================================================
    97→ * Helper functions for the rest of the ACL implementation
    98→ * ==========================================================================*/
    99→
   100→/* Return zero if strings are the same, non-zero if they are not.
   101→ * The comparison is performed in a way that prevents an attacker to obtain
   102→ * information about the nature of the strings just monitoring the execution
   103→ * time of the function.
   104→ *
   105→ * Note that limiting the comparison length to strings up to 512 bytes we
   106→ * can avoid leaking any information about the password length and any
   107→ * possible branch misprediction related leak.
   108→ */
   109→int time_independent_strcmp(char *a, char *b) {
   110→    char bufa[CONFIG_AUTHPASS_MAX_LEN], bufb[CONFIG_AUTHPASS_MAX_LEN];
   111→    /* The above two strlen perform len(a) + len(b) operations where either
   112→     * a or b are fixed (our password) length, and the difference is only
   113→     * relative to the length of the user provided string, so no information
   114→     * leak is possible in the following two lines of code. */
   115→    unsigned int alen = strlen(a);
   116→    unsigned int blen = strlen(b);
   117→    unsigned int j;
   118→    int diff = 0;
   119→
   120→    /* We can't compare strings longer than our static buffers.
   121→     * Note that this will never pass the first test in practical circumstances
   122→     * so there is no info leak. */
   123→    if (alen > sizeof(bufa) || blen > sizeof(bufb)) return 1;
   124→
   125→    memset(bufa,0,sizeof(bufa));        /* Constant time. */
   126→    memset(bufb,0,sizeof(bufb));        /* Constant time. */
   127→    /* Again the time of the following two copies is proportional to
   128→     * len(a) + len(b) so no info is leaked. */
   129→    memcpy(bufa,a,alen);
   130→    memcpy(bufb,b,blen);
   131→
   132→    /* Always compare all the chars in the two buffers without
   133→     * conditional expressions. */
   134→    for (j = 0; j < sizeof(bufa); j++) {
   135→        diff |= (bufa[j] ^ bufb[j]);
   136→    }
   137→    /* Length must be equal as well. */
   138→    diff |= alen ^ blen;
   139→    return diff; /* If zero strings are the same. */
   140→}
   141→
   142→/* =============================================================================
   143→ * Low level ACL API
   144→ * ==========================================================================*/
   145→
   146→/* Given the category name the command returns the corresponding flag, or
   147→ * zero if there is no match. */
   148→uint64_t ACLGetCommandCategoryFlagByName(const char *name) {
   149→    for (int j = 0; ACLCommandCategories[j].flag != 0; j++) {
   150→        if (!strcasecmp(name,ACLCommandCategories[j].name)) {
   151→            return ACLCommandCategories[j].flag;
   152→        }
   153→    }
   154→    return 0; /* No match. */
   155→}
   156→
   157→/* Method for passwords/pattern comparison used for the user->passwords list
   158→ * so that we can search for items with listSearchKey(). */
   159→int ACLListMatchSds(void *a, void *b) {
   160→    return sdscmp(a,b) == 0;
   161→}
   162→
   163→/* Method to free list elements from ACL users password/ptterns lists. */
   164→void ACLListFreeSds(void *item) {
   165→    sdsfree(item);
   166→}
   167→
   168→/* Method to duplicate list elements from ACL users password/ptterns lists. */
   169→void *ACLListDupSds(void *item) {
   170→    return sdsdup(item);
   171→}
   172→
   173→/* Create a new user with the specified name, store it in the list
   174→ * of users (the Users global radix tree), and returns a reference to
   175→ * the structure representing the user.
   176→ *
   177→ * If the user with such name already exists NULL is returned. */
   178→user *ACLCreateUser(const char *name, size_t namelen) {
   179→    if (raxFind(Users,(unsigned char*)name,namelen) != raxNotFound) return NULL;
   180→    user *u = zmalloc(sizeof(*u));
   181→    u->name = sdsnewlen(name,namelen);
   182→    u->flags = USER_FLAG_DISABLED;
   183→    u->allowed_subcommands = NULL;
   184→    u->passwords = listCreate();
   185→    u->patterns = listCreate();
   186→    listSetMatchMethod(u->passwords,ACLListMatchSds);
   187→    listSetFreeMethod(u->passwords,ACLListFreeSds);
   188→    listSetDupMethod(u->passwords,ACLListDupSds);
   189→    listSetMatchMethod(u->patterns,ACLListMatchSds);
   190→    listSetFreeMethod(u->patterns,ACLListFreeSds);
   191→    listSetDupMethod(u->patterns,ACLListDupSds);
   192→    memset(u->allowed_commands,0,sizeof(u->allowed_commands));
   193→    raxInsert(Users,(unsigned char*)name,namelen,u,NULL);
   194→    return u;
   195→}
   196→
   197→/* This function should be called when we need an unlinked "fake" user
   198→ * we can use in order to validate ACL rules or for other similar reasons.
   199→ * The user will not get linked to the Users radix tree. The returned
   200→ * user should be released with ACLFreeUser() as usually. */
   201→user *ACLCreateUnlinkedUser(void) {
   202→    char username[64];
   203→    for (int j = 0; ; j++) {
   204→        snprintf(username,sizeof(username),"__fakeuser:%d__",j);
   205→        user *fakeuser = ACLCreateUser(username,strlen(username));
   206→        if (fakeuser == NULL) continue;
   207→        int retval = raxRemove(Users,(unsigned char*) username,
   208→                               strlen(username),NULL);
   209→        serverAssert(retval != 0);
   210→        return fakeuser;
   211→    }
   212→}
   213→
   214→/* Release the memory used by the user structure. Note that this function
   215→ * will not remove the user from the Users global radix tree. */
   216→void ACLFreeUser(user *u) {
   217→    sdsfree(u->name);
   218→    listRelease(u->passwords);
   219→    listRelease(u->patterns);
   220→    ACLResetSubcommands(u);
   221→    zfree(u);
   222→}
