   722→        sds newpat = sdsnewlen(op+1,oplen-1);
   723→        listNode *ln = listSearchKey(u->patterns,newpat);
   724→        /* Avoid re-adding the same pattern multiple times. */
   725→        if (ln == NULL) listAddNodeTail(u->patterns,newpat);
